INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '191235b6-695e-468e-a210-6c1755025d70',
  '00000000-0000-0000-0000-000000000001',
  $escape$Express DI — Manual Wiring vs Containers and What It Costs You at Test Time$escape$,
  $escape$Express has no built-in DI container. Most apps default to manual wiring: importing service modules directly inside route handlers or middleware. This couples your routes to concrete implementations — swapping a real `UserRepository` for a fake in tests requires monkey-patching `require` cache or restructuring modules mid-test.

The practical alternative is a thin container like `awilix`. You register your services once in a composition root (`container.js`), then use `makeInvoker` or scope-based resolution to inject dependencies into your Express route handlers at request time. Each handler receives its deps as arguments rather than closing over imported singletons.

The testability payoff is immediate: unit-test a handler by passing a mock `userService` object directly — no module mocking, no `jest.mock()` gymnastics. Integration tests can swap the entire database layer by re-registering one token in a test container.

The tradeoff is ceremony. For small Express apps (< 10 routes), manual wiring is perfectly fine. Once you hit shared services, request-scoped lifetimes (e.g., per-request DB transactions), or team-scale codebases, a container pays for itself in test isolation alone.$escape$,
  $escape$// container.js (awilix)
import { createContainer, asClass, asValue, Lifetime } from 'awilix';
import { UserService } from './services/UserService.js';
import { db } from './db.js';

export const container = createContainer();
container.register({
  userService: asClass(UserService, { lifetime: Lifetime.SCOPED }),
  db: asValue(db),
});

// routes/users.js
import { makeInvoker } from 'awilix-express';
const api = makeInvoker(({ userService }) => ({
  getUser: async (req, res) => {
    const user = await userService.findById(req.params.id);
    res.json(user);
  },
}));
export default (router) => router.get('/:id', api('getUser'));$escape$,
  $escape$javascript$escape$,
