INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'c02e9362-1119-45c8-ba8f-8c636e4c863b',
  '00000000-0000-0000-0000-000000000001',
  $escape$Express Input Validation — Schema Validation at the Boundary with Zod$escape$,
  $escape$Never trust req.body, req.query, or req.params. Validate at the route handler boundary before any business logic runs. Zod paired with a thin Express middleware is the cleanest pattern: define a schema, parse incoming data, and short-circuit with a 422 if it fails.

Use z.object() to describe the expected shape, then call schema.safeParse() — it never throws, returning { success, data, error } instead. On failure, map error.issues into a structured 422 response so clients get field-level feedback. On success, replace req.body with the parsed (typed, coerced) data to prevent prototype pollution and strip unknown keys automatically.

Sanitization is implicit: Zod strips extra fields by default with .strict() or .strip(), and coerces types when you use z.coerce.string(). For SQL-facing params, lean on parameterized queries — never concatenate validated strings into raw SQL.

Wrap the middleware in a reusable validate(schema) factory so every route stays declarative: router.post('/users', validate(createUserSchema), createUser). Keeps handlers clean and validation testable in isolation.$escape$,
  $escape$import { z } from 'zod';
import { Request, Response, NextFunction } from 'express';

const createUserSchema = z.object({
  email: z.string().email(),
  age: z.coerce.number().int().min(13),
});

function validate(schema: z.ZodTypeAny) {
  return (req: Request, res: Response, next: NextFunction) => {
    const result = schema.safeParse(req.body);
    if (!result.success) {
      res.status(422).json({ errors: result.error.issues });
      return;
    }
    req.body = result.data;
    next();
  };
}

router.post('/users', validate(createUserSchema), createUser);$escape$,
  $escape$typescript$escape$,
