INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '501db68e-40ba-4ecf-8428-ddf594bb8a8a',
  '00000000-0000-0000-0000-000000000001',
  $escape$Express Testing — Unit vs Integration, Mocking HTTP, and Test DB Strategy$escape$,
  $escape$Unit-test Express route handlers in isolation by extracting them from the router and calling them with mock `req`/`res` objects — no server needed. Integration tests should spin up the actual Express app using `supertest`, which lets you fire real HTTP requests against `app.listen(0)` (ephemeral port) without a running server process.

For outbound HTTP calls (e.g., third-party APIs called inside middleware or route handlers), use `nock` to intercept and stub `http`/`https` requests at the Node.js layer — no need to wrap fetch in an abstraction.

For the database, never hit production or a shared dev DB. Options in priority order: (1) spin up a dedicated Postgres instance via `docker-compose` in CI, seeding with fixtures before each test suite; (2) use `pg-mem` for pure in-memory SQL — fast but limited dialect support; (3) wrap each test in a transaction and roll it back in `afterEach`. The transaction rollback pattern works cleanly with `pg` pool clients passed explicitly through Express's `req.db` pattern.$escape$,
  $escape$import request from 'supertest';
import nock from 'nock';
import app from '../app';
import { pool } from '../db';

beforeEach(async () => {
  await pool.query('BEGIN');
});

afterEach(async () => {
  await pool.query('ROLLBACK');
});

test('GET /users/:id fetches from GitHub API', async () => {
  nock('https://api.github.com').get('/users/octocat').reply(200, { login: 'octocat' });
  const res = await request(app).get('/users/octocat');
  expect(res.status).toBe(200);
  expect(res.body.login).toBe('octocat');
});$escape$,
  $escape$javascript$escape$,
