INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '17017c93-756d-4dd6-b87a-0936f7f5b26d',
  '00000000-0000-0000-0000-000000000001',
  $escape$Express Performance — Connection Pooling, Async Handlers, and Response Compression$escape$,
  $escape$Express itself doesn't manage database connections — that's on you. Pair `pg` with `pg-pool` and create a single pool instance at startup, not per-request. A pool misconfigured with `max: 1` will serialize every DB call under load. Set `max` to 10–20 and reuse the same pool across all route handlers via `app.locals.pool` or a dedicated module.

Express 5 handles async errors natively, but on Express 4 you must wrap async handlers or uncaught rejections silently drop. Use a thin wrapper — `asyncHandler(fn)` — that calls `next(err)` on rejection, keeping your error middleware in the loop.

For response compression, `compression` middleware with default settings uses gzip and skips responses under 1KB (the `threshold` option). Mount it early — before routes — so it intercepts all text-based responses including JSON APIs. Set `filter` to exclude already-compressed formats like images or pre-gzipped assets to avoid wasted CPU.$escape$,
  $escape$import express from 'express';
import compression from 'compression';
import pg from 'pg';

const pool = new pg.Pool({ max: 15, idleTimeoutMillis: 30000 });
const app = express();

app.locals.pool = pool;
app.use(compression({ threshold: 1024 }));

const asyncHandler = (fn) => (req, res, next) => Promise.resolve(fn(req, res, next)).catch(next);

app.get('/users', asyncHandler(async (req, res) => {
  const { rows } = await req.app.locals.pool.query('SELECT id, name FROM users LIMIT 50');
  res.json(rows);
}));

app.use((err, req, res, next) => res.status(500).json({ error: err.message }));$escape$,
  $escape$javascript$escape$,
