INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '4329506c-a9ec-42b4-b70b-c9f7cf567a2e',
  '00000000-0000-0000-0000-000000000001',
  $escape$Express Config Done Right — env-var, Settings Object, and Secrets Management$escape$,
  $escape$Scattering `process.env.SOME_VAR` throughout your Express app is a maintenance trap. Instead, centralize all config into a validated settings object loaded once at startup. Use the `dotenv` package to populate `process.env` from `.env` files, but never ship that file — only ship `.env.example`. Validate required vars eagerly so the app crashes at boot, not mid-request. For secrets like DB passwords or API keys, prefer environment injection via your hosting platform (Azure App Service config, Docker secrets, GitHub Actions secrets) rather than hardcoded `.env` files in production. Pass the config object into your Express app via `app.set('config', config)` and retrieve it anywhere with `req.app.get('config')` — no global singletons, no import coupling. For strongly-typed setups, wrap the raw `process.env` reads in a single module and export a frozen object. This way, rotating a secret means updating one env var, not hunting down 12 scattered references across your route handlers.$escape$,
  $escape$import 'dotenv/config';

function loadConfig() {
  const required = ['DATABASE_URL', 'JWT_SECRET', 'PORT'];
  for (const key of required) {
    if (!process.env[key]) throw new Error(`Missing required env var: ${key}`);
  }
  return Object.freeze({
    db:  { url: process.env.DATABASE_URL! },
    jwt: { secret: process.env.JWT_SECRET!, expiresIn: process.env.JWT_EXPIRES_IN ?? '7d' },
    port: parseInt(process.env.PORT!, 10),
  });
}

export type AppConfig = ReturnType<typeof loadConfig>;
export const config = loadConfig();

// In app setup:
// app.set('config', config);
// In a route: const cfg = req.app.get('config') as AppConfig;$escape$,
  $escape$typescript$escape$,
