INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '22fbe137-bd0f-49e3-bd85-3439872e8413',
  '00000000-0000-0000-0000-000000000001',
  $escape$Express Structured Logging — Correlation IDs and Request Middleware Done Right$escape$,
  $escape$Every Express request should carry a correlation ID — a UUID that ties together every log line, downstream call, and error for that request. Without it, debugging distributed failures across logs is guesswork.

Attach a correlation ID in an early middleware using `AsyncLocalStorage` or by stamping `req.id`. Libraries like `express-request-id` automate this, but rolling your own gives full control. Pass the ID to your logger via a child logger bound to `{ correlationId: req.id }`.

For structured logs, replace `console.log` with `pino` — it emits newline-delimited JSON natively, which log aggregators (Datadog, Loki) parse without config. Use `pino-http` as your request logging middleware: it wraps the `res.on('finish')` event to log method, URL, status code, and response time in a single structured line.

Key pattern: create the child logger in middleware, attach it to `req.log`, and call `req.log.info(...)` in your route handlers. This keeps correlation ID automatic — no manual threading required.$escape$,
  $escape$import express from 'express';
import pino from 'pino';
import pinoHttp from 'pino-http';
import { randomUUID } from 'crypto';

const logger = pino({ level: 'info' });
const app = express();

app.use(pinoHttp({
  logger,
  genReqId: (req) => req.headers['x-correlation-id'] ?? randomUUID(),
  customSuccessMessage: (req, res) => `${req.method} ${req.url} completed`,
}));

app.get('/users/:id', (req, res) => {
  req.log.info({ userId: req.params.id }, 'Fetching user');
  res.json({ id: req.params.id });
});$escape$,
  $escape$javascript$escape$,
