INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'd738f6bc-7518-4dad-ae60-3a5e6b0134b7',
  '00000000-0000-0000-0000-000000000001',
  $escape$Express Background Jobs — Bull Queues and Worker Process Patterns$escape$,
  $escape$Express itself has no built-in job queue — you wire one in. Bull (backed by Redis) is the de facto choice. The pattern: your Express route enqueues a job and returns immediately; a separate worker process consumes it. Keep the worker in a dedicated file and spawn it independently so a crashing worker never takes down your API server.

Define queues in a shared module so both the API and worker import the same Bull instance. In the worker, call `queue.process(concurrency, handler)` — never call this in the Express process or you'll process jobs on your web server's event loop, blocking requests under load.

For scheduled jobs, use `queue.add(data, { repeat: { cron: '0 * * * *' } })` instead of `node-cron` inside Express — Bull's scheduler survives restarts and won't double-fire across multiple API replicas. Use `queue.on('failed', (job, err))` for dead-letter handling. Always set `removeOnComplete` and `removeOnFail` limits to prevent Redis bloat in long-running deployments.$escape$,
  $escape$// shared/queues.js
const Bull = require('bull');
exports.emailQueue = new Bull('email', { redis: process.env.REDIS_URL });

// routes/users.js (Express process)
router.post('/register', async (req, res) => {
  const user = await createUser(req.body);
  await emailQueue.add({ userId: user.id }, { attempts: 3, backoff: 5000 });
  res.status(201).json(user); // returns before email sends
});

// workers/email-worker.js (separate process)
const { emailQueue } = require('../shared/queues');
emailQueue.process(5, async (job) => {
  await sendWelcomeEmail(job.data.userId);
});
emailQueue.on('failed', (job, err) => console.error(`Job ${job.id} failed:`, err));$escape$,
