INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '2b01ffba-0926-4b36-9265-a2466b56448d',
  '00000000-0000-0000-0000-000000000001',
  $escape$Express Monitoring — Health Checks, Prometheus Metrics, and Distributed Tracing$escape$,
  $escape$Express has no built-in observability, so you wire it yourself. For health checks, expose a `/health` route that probes real dependencies — don't just return 200. Check your DB connection, cache reachability, and disk space. For metrics, mount `prom-client` on a separate `/metrics` route (ideally a dedicated internal port via a second `http.createServer`) to prevent public exposure. Register a `collectDefaultMetrics()` call at startup for Node.js runtime stats, then add custom `Counter` and `Histogram` instances for request rates and latency. Use `express-prom-bundle` to auto-instrument every route with `http_request_duration_seconds`. For distributed tracing, instrument with OpenTelemetry: initialize `NodeTracerProvider` before `require('express')`, then use `ExpressInstrumentation` and `HttpInstrumentation` from `@opentelemetry/instrumentation-express` and `@opentelemetry/instrumentation-http`. This auto-patches `app.use()` and propagates W3C `traceparent` headers across services. Export spans to a Jaeger or OTLP collector. Keep your health, metrics, and trace endpoints on separate middleware stacks so a slow metrics scrape never blocks user traffic.$escape$,
  $escape$import express from 'express';
import http from 'http';
import client from 'prom-client';
import promBundle from 'express-prom-bundle';

client.collectDefaultMetrics();

const app = express();
app.use(promBundle({ includeMethod: true, includePath: true }));

app.get('/health', async (req, res) => {
  const dbOk = await checkDb(); // your own probe
  res.status(dbOk ? 200 : 503).json({ db: dbOk ? 'ok' : 'down' });
});

// Expose /metrics on internal port 9090 only
const metricsApp = express();
metricsApp.get('/metrics', async (req, res) => {
  res.set('Content-Type', client.register.contentType);
  res.end(await client.register.metrics());
});
http.createServer(metricsApp).listen(9090);

app.listen(3000);$escape$,
  $escape$javascript$escape$,
