INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'c38e740c-00bb-4aa5-984b-c068a5d2c044',
  '00000000-0000-0000-0000-000000000001',
  $escape$Express Has No Batteries — Here's What You Wire Yourself$escape$,
  $escape$Express gives you request/response, routing, and middleware — nothing else. No auto-generated OpenAPI docs like FastAPI's `/docs`, no decorator-driven controllers like NestJS's `@Controller`, no built-in ORM like Django's admin panel, no server-side reactivity like Phoenix LiveView. Every capability is an explicit `app.use()` call you assemble yourself.

For API docs, add `swagger-ui-express` + `swagger-jsdoc` and mount the UI at a route. For structured modules, compose `express.Router()` instances per domain and attach them to a root app. For dependency injection, pass services through middleware via `res.locals` or adopt `awilix`. For real-time, attach `socket.io` to the same `http.Server` instance Express wraps.

The trade-off is stark: maximum flexibility, zero convention. NestJS exists to solve this exact friction — it layers decorators, DI, and module boundaries directly on top of Express (or Fastify). When your Express app starts growing its own `@Controller` abstractions and barrel-file module patterns, you're rebuilding NestJS by hand. At that point, the minimal core stops being an asset.$escape$,
  $escape$const express = require('express');
const swaggerUi = require('swagger-ui-express');
const swaggerDocument = require('./openapi.json');
const { createContainer, asClass } = require('awilix');

const app = express();
const container = createContainer();
container.register({ userService: asClass(UserService).singleton() });

app.use(express.json());
app.use('/api-docs', swaggerUi.serve, swaggerUi.setup(swaggerDocument));
app.use((req, res, next) => {
  res.locals.userService = container.resolve('userService');
  next();
});

const userRouter = require('./routes/users');
app.use('/users', userRouter);

app.listen(3000);$escape$,
  $escape$javascript$escape$,
